@@ -103,7 +103,8 @@ static void emit_ansi_start(asx_report_buf *out, const asx_console_style *style)
     if (style->dim) asx_report_buf_append(out, "2;");
     if (style->italic) asx_report_buf_append(out, "3;");
     if (style->underline) asx_report_buf_append(out, "4;");
-    if (style->fg != ASX_COLOR_DEFAULT) {
+    /* Emit foreground color: 30-37 for named colors, 39 for default */
+    {
         char fg_code[4];
         fg_code[0] = '3';
         fg_code[1] = (char)('0' + (int)style->fg);

@@ -6,6 +6,7 @@

 #include <asx/observability/observability.h>
 #include <asx/runtime/runtime.h>
+#include <limits.h>
 #include <string.h>

 /* ------------------------------------------------------------------ */
@@ -107,7 +108,14 @@ asx_status asx_metrics_observe(asx_metrics *m, const char *name, int64_t value)
     if (e == NULL) return ASX_E_NOT_FOUND;
     if (e->type != ASX_METRIC_HISTOGRAM) return ASX_E_INVALID_STATE;
     e->count++;
-    e->sum += value;
+    /* Overflow-safe sum: clamp at INT64_MAX/MIN instead of wrapping */
+    if (value > 0 && e->sum > INT64_MAX - value) {
+        e->sum = INT64_MAX;
+    } else if (value < 0 && e->sum < INT64_MIN - value) {
+        e->sum = INT64_MIN;
+    } else {
+        e->sum += value;
+    }
     if (value < e->min_val) e->min_val = value;
     if (value > e->max_val) e->max_val = value;
     return ASX_OK;
